            byte[] abiHandle = { 81, 231, 198, 187 };
            var trait_idAbi = new AVM.ClientGenerator.ABI.ARC4.Types.VariableArray<AVM.ClientGenerator.ABI.ARC4.Types.Byte>("byte"); trait_idAbi.From(trait_id);
